package com.restaurantcraft.entity.ai; import com.restaurantcraft.entity.*; import net.minecraft.world.entity.ai.goal.Goal; public class MoveToRestaurantExitGoal extends Goal { private final CustomerEntity c; public MoveToRestaurantExitGoal(CustomerEntity c){this.c=c;} public boolean canUse(){return c.state()==CustomerState.LEAVING&&c.exitPos()!=null;} public void tick(){c.getNavigation().moveTo(c.exitPos().getX()+0.5,c.exitPos().getY(),c.exitPos().getZ()+0.5,1.0);} }
